{
  "command": "TASK='.ypi/tasks/20260713-134601-优化-chat-顶部-session-速率-计费-上下文为标签化展示-并支持子-session-';
printf '%s\n' 'Artifact headings:'; for f in brief prd ui design implement checks plan-review; do printf '%-12s ' "$f"; head -n 1 "$TASK/$f.md"; done;
printf '%s\n' 'TBD scan:'; rg -n '_TBD|# (brief|prd|ui|design|implement|checks|plan review)$' "$TASK"/{brief,prd,ui,design,implement,checks,plan-review}.md || true;
python3 - <<'PY'
import json,re,pathlib
p=pathlib.Path('.ypi/tasks/20260713-134601-优化-chat-顶部-session-速率-计费-上下文为标签化展示-并支持子-session-/implement.md')
s=p.read_text()
m=re.search(r'```json ypi-implementation-plan\n(.*?)\n```',s,re.S)
assert m, 'implementation plan block missing'
data=json.loads(m.group(1))
assert data['schemaVersion']==2 and len(data['subtasks'])==7
ids={x['id'] for x in data['subtasks']}
for x in data['subtasks']:
    assert set(x['dependsOn']) <= ids
    for k in ['id','title','phase','order','dependsOn','files','instructions','acceptance','validation','risks','parallelizable','localReview']:
        assert k in x,(x['id'],k)
print('implementation plan JSON: valid; subtasks=',len(data['subtasks']))
PY
printf '%s\n' 'Task state:'; node -e "const t=require('./$TASK/task.json'); console.log(t.status, Boolean(t.implementationPlan), t.currentMember)";
printf '%s\n' 'Git status:'; git status --short -- "$TASK"",
  "timeout": 20
}

